{"type":"permission_request","request_id":"perm-1773156363489-9aipnhp","agent_id":"csvutil","tool_name":"Write","tool_use_id":"toolu_01HMJPRn9p37XvBtZVbBJNHi","description":"Write a file to the local filesystem.","input":{"file_path":"/home/ketan/project/kapow/.claude/worktrees/worktree/csvutil/tools/kapow/internal/csvutil/csvutil.go","content":"package csvutil

import (
	"encoding/csv"
	"fmt"
	"io"
	"strconv"
)

// Option configures a Reader.
type Option func(*Reader)

// WithDelimiter sets the field delimiter (default: ',').
func WithDelimiter(r rune) Option {
	return func(cr *Reader) {
		cr.csv.Comma = r
	}
}

// WithLazyQuotes allows bare quotes in non-quoted fields and non-doubled quotes
// in quoted fields (encoding/csv LazyQuotes mode).
func WithLazyQuotes(b bool) Option {
	return func(cr *Reader) {
		cr.csv.LazyQuotes = b
	}
}

// Reader wraps encoding/csv and maps columns by header name.
// Call Next to iterate rows; each row provides named-column accessors.
type Reader struct {
	csv     *csv.Reader
	headers map[string]int
}

// NewReader creates a Reader, reads the first line as column headers, and
// applies any provided options. Returns an error if the header row cannot be
// read or parsed.
func NewReader(r io.Reader, opts ...Option) (*Reader, error) {
	cr := &Reader{
		csv: csv.NewReader(r),
	}
	// Apply options before reading headers so delimiter etc. take effect.
	for _, o := range opts {
		o(cr)
	}

	headers, err := cr.csv.Read()
	if err != nil {
		return nil, fmt.Errorf("csvutil: read headers: %w", err)
	}

	cr.headers = make(map[string]int, len(headers))
	for i, h := range headers {
		cr.headers[h] = i
	}

	return cr, nil
}

// Next advances to the next record and returns a Row for it.
// Returns (Row{}, false, nil) at EOF.
func (r *Reader) Next() (Row, bool, error) {
	record, err := r.csv.Read()
	if err == io.EOF {
		return Row{}, false, nil
	}
	if err != nil {
		return Row{}, false, fmt.Errorf("csvutil: read row: %w", err)
	}
	return Row{values: record, headers: r.headers}, true, nil
}

// Row holds one parsed record with header-mapped field accessors.
// All accessors are silent on missing columns: they return the zero value or nil.
type Row struct {
	values  []string
	headers map[string]int
}

// raw returns the raw string value for col, and whether the column exists.
func (r Row) raw(col string) (string, bool) {
	idx, ok := r.headers[col]
	if !ok || idx >= len(r.values) {
		return "", false
	}
	return r.values[idx], true
}

// String returns the string value of col, or "" if the column is absent.
func (r Row) String(col string) string {
	v, _ := r.raw(col)
	return v
}

// Int parses col as an integer, returning 0 on missing column or parse error.
func (r Row) Int(col string) int {
	v, ok := r.raw(col)
	if !ok || v == "" {
		return 0
	}
	n, err := strconv.Atoi(v)
	if err != nil {
		return 0
	}
	return n
}

// Float parses col as a float64, returning 0 on missing column or parse error.
func (r Row) Float(col string) float64 {
	v, ok := r.raw(col)
	if !ok || v == "" {
		return 0
	}
	f, err := strconv.ParseFloat(v, 64)
	if err != nil {
		return 0
	}
	return f
}

// OptionalString returns a pointer to the string value of col, or nil if the
// column is absent or the value is empty.
func (r Row) OptionalString(col string) *string {
	v, ok := r.raw(col)
	if !ok || v == "" {
		return nil
	}
	return &v
}

// OptionalInt parses col as an integer and returns a pointer to the result, or
// nil if the column is absent, empty, or not parseable as an integer.
func (r Row) OptionalInt(col string) *int {
	v, ok := r.raw(col)
	if !ok || v == "" {
		return nil
	}
	n, err := strconv.Atoi(v)
	if err != nil {
		return nil
	}
	return &n
}

// OptionalFloat parses col as a float64 and returns a pointer to the result,
// or nil if the column is absent, empty, or not parseable as a float.
func (r Row) OptionalFloat(col string) *float64 {
	v, ok := r.raw(col)
	if !ok || v == "" {
		return nil
	}
	f, err := strconv.ParseFloat(v, 64)
	if err != nil {
		return nil
	}
	return &f
}
"},"permission_suggestions":[{"type":"setMode","mode":"acceptEdits","destination":"session"}]}

{"type":"permission_request","request_id":"perm-1773156405564-yclvmvg","agent_id":"csvutil","tool_name":"Write","tool_use_id":"toolu_0163oxP2uohWTqV8MGgGectV","description":"Write a file to the local filesystem.","input":{"file_path":"/home/ketan/project/kapow/.claude/worktrees/worktree/csvutil/tools/kapow/internal/csvutil/csvutil_test.go","content":"package csvutil

import (
	"strings"
	"testing"
)

const csvData = `name,age,score,city
Alice,30,9.5,New York
Bob,25,8.1,
Charlie,0,,Paris
`

const tsvData = "name\tage\tscore\n" +
	"Alice\t30\t9.5\n" +
	"Bob\t25\t8.1\n"

const quotedCSV = `name,description,value
Alice,"tall, blonde, and smart",42
Bob,"says ""hello"" often",7
Carol,"line1
line2",99
`

const headerOnlyCSV = "name,age,score\n"

func mustReader(t *testing.T, data string, opts ...Option) *Reader {
	t.Helper()
	r, err := NewReader(strings.NewReader(data), opts...)
	if err != nil {
		t.Fatalf("NewReader: %v", err)
	}
	return r
}

func collectRows(t *testing.T, r *Reader) []Row {
	t.Helper()
	var rows []Row
	for {
		row, ok, err := r.Next()
		if err != nil {
			t.Fatalf("Next: %v", err)
		}
		if !ok {
			break
		}
		rows = append(rows, row)
	}
	return rows
}

// 1. Normal CSV parsing.
func TestNormalCSV(t *testing.T) {
	r := mustReader(t, csvData)
	rows := collectRows(t, r)

	if len(rows) != 3 {
		t.Fatalf("want 3 rows, got %d", len(rows))
	}

	if got := rows[0].String("name"); got != "Alice" {
		t.Errorf("row[0] name: want Alice, got %q", got)
	}
	if got := rows[0].Int("age"); got != 30 {
		t.Errorf("row[0] age: want 30, got %d", got)
	}
	if got := rows[0].Float("score"); got != 9.5 {
		t.Errorf("row[0] score: want 9.5, got %f", got)
	}
	if got := rows[1].String("name"); got != "Bob" {
		t.Errorf("row[1] name: want Bob, got %q", got)
	}
}

// 2. TSV parsing via WithDelimiter.
func TestTSV(t *testing.T) {
	r := mustReader(t, tsvData, WithDelimiter('\t'))
	rows := collectRows(t, r)

	if len(rows) != 2 {
		t.Fatalf("want 2 rows, got %d", len(rows))
	}
	if got := rows[0].String("name"); got != "Alice" {
		t.Errorf("row[0] name: want Alice, got %q", got)
	}
	if got := rows[0].Int("age"); got != 30 {
		t.Errorf("row[0] age: want 30, got %d", got)
	}
	if got := rows[1].Float("score"); got != 8.1 {
		t.Errorf("row[1] score: want 8.1, got %f", got)
	}
}

// 3. Missing columns return zero/nil.
func TestMissingColumn(t *testing.T) {
	r := mustReader(t, csvData)
	rows := collectRows(t, r)

	row := rows[0]

	if got := row.String("nonexistent"); got != "" {
		t.Errorf("missing String: want empty, got %q", got)
	}
	if got := row.Int("nonexistent"); got != 0 {
		t.Errorf("missing Int: want 0, got %d", got)
	}
	if got := row.Float("nonexistent"); got != 0 {
		t.Errorf("missing Float: want 0, got %f", got)
	}
	if got := row.OptionalString("nonexistent"); got != nil {
		t.Errorf("missing OptionalString: want nil, got %v", got)
	}
	if got := row.OptionalInt("nonexistent"); got != nil {
		t.Errorf("missing OptionalInt: want nil, got %v", got)
	}
	if got := row.OptionalFloat("nonexistent"); got != nil {
		t.Errorf("missing OptionalFloat: want nil, got %v", got)
	}
}

// 4. Type coercion — Int and Float parse correctly.
func TestTypeCoercion(t *testing.T) {
	r := mustReader(t, csvData)
	rows := collectRows(t, r)

	// row[0]: age=30, score=9.5
	if got := rows[0].Int("age"); got != 30 {
		t.Errorf("Int coercion: want 30, got %d", got)
	}
	if got := rows[0].Float("score"); got != 9.5 {
		t.Errorf("Float coercion: want 9.5, got %f", got)
	}
	// row[2]: age=0 (explicit zero), score="" (empty → 0)
	if got := rows[2].Int("age"); got != 0 {
		t.Errorf("Int zero: want 0, got %d", got)
	}
	if got := rows[2].Float("score"); got != 0 {
		t.Errorf("Float empty: want 0, got %f", got)
	}
}

// 5. Quoted values with embedded commas and newlines.
func TestQuotedValues(t *testing.T) {
	r := mustReader(t, quotedCSV)
	rows := collectRows(t, r)

	if len(rows) != 3 {
		t.Fatalf("want 3 rows, got %d", len(rows))
	}
	if got := rows[0].String("description"); got != "tall, blonde, and smart" {
		t.Errorf("quoted comma: got %q", got)
	}
	if got := rows[1].String("description"); got != `says "hello" often` {
		t.Errorf("quoted double-quote: got %q", got)
	}
	if got := rows[2].String("description"); got != "line1\nline2" {
		t.Errorf("quoted newline: got %q", got)
	}
}

// 6. LazyQuotes handles malformed (bare) quotes.
func TestLazyQuotes(t *testing.T) {
	data := "name,note\nAlice,she said \"hello\"\nBob,fine\n"
	r := mustReader(t, data, WithLazyQuotes(true))
	rows := collectRows(t, r)

	if len(rows) != 2 {
		t.Fatalf("want 2 rows, got %d", len(rows))
	}
	if got := rows[0].String("name"); got != "Alice" {
		t.Errorf("lazy quote row name: got %q", got)
	}
}

// 7. Optional accessors return nil for empty cells and missing columns.
func TestOptionalEmptyFields(t *testing.T) {
	r := mustReader(t, csvData)
	rows := collectRows(t, r)

	// row[1]: city="" (empty)
	if got := rows[1].OptionalString("city"); got != nil {
		t.Errorf("empty OptionalString: want nil, got %v", *got)
	}
	// row[2]: score="" (empty)
	if got := rows[2].OptionalFloat("score"); got != nil {
		t.Errorf("empty OptionalFloat: want nil, got %v", *got)
	}
	// Non-empty value should not be nil.
	if got := rows[0].OptionalString("name"); got == nil || *got != "Alice" {
		t.Errorf("non-empty OptionalString: want Alice, got %v", got)
	}
	if got := rows[0].OptionalInt("age"); got == nil || *got != 30 {
		t.Errorf("non-empty OptionalInt: want 30, got %v", got)
	}
	if got := rows[0].OptionalFloat("score"); got == nil || *got != 9.5 {
		t.Errorf("non-empty OptionalFloat: want 9.5, got %v", got)
	}
}

// 8. EOF: Next returns false, nil at end of file.
func TestEOF(t *testing.T) {
	const single = "name,age\nAlice,30\n"
	r := mustReader(t, single)

	_, ok, err := r.Next()
	if err != nil || !ok {
		t.Fatalf("first Next: ok=%v err=%v", ok, err)
	}
	_, ok, err = r.Next()
	if err != nil {
		t.Fatalf("EOF Next returned error: %v", err)
	}
	if ok {
		t.Error("EOF Next: want ok=false")
	}
}

// 9. Header-only file: Next immediately returns false.
func TestHeaderOnly(t *testing.T) {
	r := mustReader(t, headerOnlyCSV)
	_, ok, err := r.Next()
	if err != nil {
		t.Fatalf("header-only Next: %v", err)
	}
	if ok {
		t.Error("header-only: want ok=false on first Next")
	}
}

// 10. NewReader returns error on bad header read.
func TestNewReaderError(t *testing.T) {
	// An empty reader has no header line → should error.
	_, err := NewReader(strings.NewReader(""))
	if err == nil {
		t.Error("empty input: want error from NewReader, got nil")
	}
}
"},"permission_suggestions":[{"type":"setMode","mode":"acceptEdits","destination":"session"}]}

