const maxConnectAttempts = 3

// Connect establishes a connection pool to the PostgreSQL database at the given
// DSN. It retries up to 3 times with exponential backoff before returning an error.
func Connect(ctx context.Context, databaseURL string) (*pgxpool.Pool, error) {
	cfg, err := pgxpool.ParseConfig(databaseURL)
	if err != nil {
		return nil, fmt.Errorf("dbutil: failed to parse database URL: %w", err)
	}

	var pool *pgxpool.Pool
	for attempt := 1; attempt <= maxConnectAttempts; attempt++ {
		pool, err = pgxpool.NewWithConfig(ctx, cfg)
		if err != nil {
			slog.Warn("dbutil: connect attempt failed", "attempt", attempt, "error", err)
			time.Sleep(time.Duration(attempt) * time.Second)
			continue
		}

		if err = pool.Ping(ctx); err != nil {
			pool.Close()
			slog.Warn("dbutil: ping attempt failed", "attempt", attempt, "error", err)
			time.Sleep(time.Duration(attempt) * time.Second)
			continue
		}

		stat := pool.Stat()
		slog.Info("dbutil: connected", "attempt", attempt, "max_conns", stat.MaxConns())
		return pool, nil
	}

	return nil, fmt.Errorf("dbutil: failed to connect after %d attempts: %w", maxConnectAttempts, err)
}

// RefreshMaterializedViews refreshes all materialized views used by the search
// engine. Should be called after a full import run completes.
func RefreshMaterializedViews(ctx context.Context, pool *pgxpool.Pool) error {
	views := []string{
		"search_base.dataset_merged",
		"search_base.dataset_latest",
	}
	for _, view := range views {
		if _, err := pool.Exec(ctx, "REFRESH MATERIALIZED VIEW "+view); err != nil {
			return fmt.Errorf("dbutil: refresh %s: %w", view, err)
		}
		slog.Info("dbutil: refreshed materialized view", "view", view)
	}
	return nil
}
