    ope6_id            = EXCLUDED.ope6_id,
    ope8_id            = EXCLUDED.ope8_id,
    institution_name   = EXCLUDED.institution_name,
    city               = EXCLUDED.city,
    state              = EXCLUDED.state,
    nces               = COALESCE(search_base.institution.nces, '{}'::jsonb)               || COALESCE(EXCLUDED.nces,               '{}'::jsonb),
