// MergeJSONB merges two JSON objects at the Go level. Keys in src overwrite
// keys in dst. Both dst and src may be nil (treated as empty objects).
func MergeJSONB(dst, src []byte) ([]byte, error) {
	dstMap := make(map[string]json.RawMessage)
	srcMap := make(map[string]json.RawMessage)

	if len(dst) > 0 {
		if err := json.Unmarshal(dst, &dstMap); err != nil {
			return nil, fmt.Errorf("dbutil: merge jsonb: unmarshal dst: %w", err)
		}
	}
	if len(src) > 0 {
		if err := json.Unmarshal(src, &srcMap); err != nil {
			return nil, fmt.Errorf("dbutil: merge jsonb: unmarshal src: %w", err)
		}
	}

	for k, v := range srcMap {
		dstMap[k] = v
	}

	out, err := json.Marshal(dstMap)
	if err != nil {
		return nil, fmt.Errorf("dbutil: merge jsonb: marshal: %w", err)
	}
	return out, nil
}
