	b.Grow(len(s))
	for _, r := range s {
		switch {
		case unicode.IsLetter(r) || unicode.IsDigit(r) || r == ' ':
			b.WriteRune(r)
		case r == '\'' || r == '\u2019' || r == '\u2018':
			// apostrophe / curly quotes: remove without inserting a space
